var body = $input.first().json.body || $input.first().json;
var tenantId = body.tenantId;

var totalCampaignsQuery = `SELECT COUNT(*) as total FROM email_campaigns WHERE tenant_id = $1`;
var byStatusQuery = `SELECT status, COUNT(*) as count FROM email_campaigns WHERE tenant_id = $1 GROUP BY status`;
var totalSubscribersQuery = `SELECT COUNT(*) as total FROM subscriber_accounts WHERE tenant_id = $1 AND is_active = true`;
var avgRateQuery = `SELECT AVG(CASE WHEN total_envoyes > 0 THEN (total_ouverts::float / total_envoyes::float) * 100 ELSE 0 END) as avg_open_rate, AVG(CASE WHEN total_envoyes > 0 THEN (total_cliques::float / total_envoyes::float) * 100 ELSE 0 END) as avg_click_rate FROM email_campaigns WHERE tenant_id = $1 AND status = 'envoyee' AND total_envoyes > 0`;
var recentQuery = `SELECT id, tenant_id AS \"tenantId\", nom, sujet, status, sent_at AS \"sentAt\", total_envoyes AS \"totalEnvoyes\", total_ouverts AS \"totalOuverts\", total_cliques AS \"totalCliques\" FROM email_campaigns WHERE tenant_id = $1 AND status = 'envoyee' ORDER BY sent_at DESC LIMIT 5`;

var params = [tenantId];

return {
  totalCampaignsQuery: totalCampaignsQuery,
  byStatusQuery: byStatusQuery,
  totalSubscribersQuery: totalSubscribersQuery,
  avgRateQuery: avgRateQuery,
  recentQuery: recentQuery,
  params: params
};

var totalCampaigns = $node["Postgres Total Campaigns"].json[0]?.total || 0;
var byStatusResult = $node["Postgres By Status"].json || [];
var totalSubscribers = $node["Postgres Total Subscribers"].json[0]?.total || 0;
var avgRates = $node["Postgres Avg Rates"].json[0] || {};
var recentCampaigns = $node["Postgres Recent Campaigns"].json || [];

var byStatus = {};
byStatusResult.forEach(row => {
  byStatus[row.status] = row.count;
});

var avgOpenRate = avgRates.avg_open_rate ? Math.round(avgRates.avg_open_rate * 100) / 100 : 0;
var avgClickRate = avgRates.avg_click_rate ? Math.round(avgRates.avg_click_rate * 100) / 100 : 0;

return {
  stats: {
    totalCampaigns: totalCampaigns,
    byStatus: byStatus,
    totalSubscribers: totalSubscribers,
    avgOpenRate: avgOpenRate,
    avgClickRate: avgClickRate,
    recentCampaigns: recentCampaigns
  }
};
